
-- Script para criar o banco de dados e tabelas (ajustado para Age e sem Birth_Date)

CREATE DATABASE RetailAnalytics;
GO

USE RetailAnalytics;
GO

-- TABELA 1: CLIENTES (Com Versionamento)
CREATE TABLE Clientes (
    Customer_ID_Original NVARCHAR(50) PRIMARY KEY, -- Usando o Customer_ID original do CSV como chave primária
    Age INT, -- Alterado de Birth_Date para Age
    Gender NVARCHAR(50),
    Location NVARCHAR(100),
    Loyalty_Program_Member NVARCHAR(50), -- Mantido como NVARCHAR para aceitar TRUE/FALSE
    Income_Level NVARCHAR(50),
    Marital_Status NVARCHAR(50),
    Education_Level NVARCHAR(50),
    Occupation NVARCHAR(100),
    
    SysStartTime DATETIME2 GENERATED ALWAYS AS ROW START NOT NULL,
    SysEndTime DATETIME2 GENERATED ALWAYS AS ROW END NOT NULL,
    PERIOD FOR SYSTEM_TIME (SysStartTime, SysEndTime)
) 
WITH (SYSTEM_VERSIONING = ON (HISTORY_TABLE = dbo.Clientes_History));
GO

-- TABELA 2: PEDIDOS (Com Versionamento e FK)
CREATE TABLE Pedidos (
    Order_ID INT PRIMARY KEY IDENTITY(1,1), -- Adicionado IDENTITY para auto-incremento
    Customer_ID_Original NVARCHAR(50), -- Referencia o Customer_ID_Original da tabela Clientes
    Purchase_Category NVARCHAR(100),
    Product_Rating INT,
    Purchase_Amount NVARCHAR(50), -- Mantido como NVARCHAR para aceitar o formato com '$'
    Purchase_Channel NVARCHAR(50),
    Payment_Method NVARCHAR(50),
    Purchase_DateTime NVARCHAR(50), -- Mantido como NVARCHAR para aceitar o formato original
    Discount_Used NVARCHAR(50), -- Mantido como NVARCHAR para aceitar TRUE/FALSE
    Shipping_Preference NVARCHAR(50),

    SysStartTime DATETIME2 GENERATED ALWAYS AS ROW START NOT NULL,
    SysEndTime DATETIME2 GENERATED ALWAYS AS ROW END NOT NULL,
    PERIOD FOR SYSTEM_TIME (SysStartTime, SysEndTime),

    CONSTRAINT FK_Pedidos_Clientes FOREIGN KEY (Customer_ID_Original)
        REFERENCES Clientes(Customer_ID_Original) 
)
WITH (SYSTEM_VERSIONING = ON (HISTORY_TABLE = dbo.Pedidos_History));
GO

-- TABELA 3: CUSTOMER BEHAVIOR (Com Versionamento e FK)
CREATE TABLE Customer_Behavior (
    Behavior_ID INT PRIMARY KEY IDENTITY(1,1), -- Adicionado IDENTITY para auto-incremento
    Customer_ID_Original NVARCHAR(50), -- Referencia o Customer_ID_Original da tabela Clientes
    Brand_Loyalty INT,
    Time_Spent_on_Product_Research_hours INT, -- Renomeado para remover parênteses
    Social_Media_Influence NVARCHAR(50),
    Discount_Sensitivity NVARCHAR(50),
    Return_Rate NVARCHAR(50), -- Mantido como NVARCHAR para aceitar o formato original
    Customer_Satisfaction INT,
    Engagement_with_Ads NVARCHAR(50),
    Device_Used_for_Shopping NVARCHAR(50),
    Purchase_Intent NVARCHAR(50),
    Time_to_Decision INT,

    SysStartTime DATETIME2 GENERATED ALWAYS AS ROW START NOT NULL,
    SysEndTime DATETIME2 GENERATED ALWAYS AS ROW END NOT NULL,
    PERIOD FOR SYSTEM_TIME (SysStartTime, SysEndTime),

    CONSTRAINT FK_Behavior_Clientes FOREIGN KEY (Customer_ID_Original)
        REFERENCES Clientes(Customer_ID_Original)
)
WITH (SYSTEM_VERSIONING = ON (HISTORY_TABLE = dbo.Customer_Behavior_History));
GO

-- AUDITORIA DE ESTRUTURA
CREATE TABLE Log_Estrutura (
    EventType NVARCHAR(100),
    ObjectName NVARCHAR(200),
    EventDate DATETIME,
    UserName NVARCHAR(200)
);
GO

CREATE TRIGGER trg_log_estrutura
ON DATABASE
FOR CREATE_TABLE, ALTER_TABLE, DROP_TABLE
AS
BEGIN
    SET NOCOUNT ON;
    SELECT 
        EVENTDATA().value('(/EVENT_INSTANCE/EventType)[1]', 'NVARCHAR(100)'),
        EVENTDATA().value('(/EVENT_INSTANCE/ObjectName)[1]', 'NVARCHAR(200)'),
        GETDATE(),
        SYSTEM_USER;
END;
GO

