-- VIEW

USE RetailAnalytics;
GO

CREATE OR ALTER VIEW VW_MASTER_RETAIL_ANALYTICS AS
SELECT 
    -- Dados da Tabela Clientes
    C.[Customer_ID_Original],
    C.[Age],
    C.[Gender],
    C.[Location],
    C.[Loyalty_Program_Member],
    C.[Income_Level],
    C.[Marital_Status],
    C.[Education_Level],
    C.[Occupation],

    -- Dados da Tabela Pedidos
    P.[Order_ID],
    P.[Purchase_Category],
    P.[Product_Rating],
    P.[Purchase_Amount],
    P.[Purchase_Channel],
    P.[Payment_Method],
    P.[Purchase_DateTime],
    P.[Discount_Used],
    P.[Shipping_Preference],

    -- Dados da Tabela Customer Behavior
    B.[Brand_Loyalty],
    B.[Time_Spent_on_Product_Research_hours],
    B.[Social_Media_Influence],
    B.[Discount_Sensitivity],
    B.[Return_Rate],
    B.[Customer_Satisfaction],
    B.[Engagement_with_Ads],
    B.[Device_Used_for_Shopping],
    B.[Purchase_Intent],
    B.[Time_to_Decision]

FROM Clientes C
LEFT JOIN Pedidos P 
    ON C.Customer_ID_Original = P.Customer_ID_Original
LEFT JOIN Customer_Behavior B 
    ON C.Customer_ID_Original = B.Customer_ID_Original;
GO

-- Para visualizar o resultado:
SELECT * FROM VW_MASTER_RETAIL_ANALYTICS;
